  "Off = one tap (recommended). On = stricter consent (EU).": { es: "Desactivado = un toque (recomendado). Activado = consentimiento más estricto (UE).", fr: "Désactivé = un clic (recommandé). Activé = consentement plus strict (UE).", de: "Aus = ein Tipp (empfohlen). Ein = strengere Einwilligung (EU).", it: "Off = un tocco (consigliato). On = consenso più rigoroso (UE).", pt: "Desligado = um toque (recomendado). Ligado = consentimento mais rigoroso (UE).", nl: "Uit = één tik (aanbevolen). Aan = strengere toestemming (EU).", pl: "Wył. = jedno kliknięcie (zalecane). Wł. = surowsza zgoda (UE)." },
  "Where subscribers are saved": { es: "Dónde se guardan los suscriptores", fr: "Où les abonnés sont enregistrés", de: "Wo Abonnenten gespeichert werden", it: "Dove vengono salvati gli iscritti", pt: "Onde os subscritores são guardados", nl: "Waar abonnees worden opgeslagen", pl: "Gdzie zapisywani są subskrybenci" },
