  "Success message": { es: "Mensaje de éxito", fr: "Message de succès", de: "Erfolgsmeldung", it: "Messaggio di successo", pt: "Mensagem de sucesso", nl: "Succesbericht", pl: "Komunikat o powodzeniu" },
  "Low-stock text": { es: "Texto de pocas existencias", fr: "Texte de stock faible", de: "Text für geringen Bestand", it: "Testo scorte basse", pt: "Texto de stock baixo", nl: "Tekst lage voorraad", pl: "Tekst niskiego stanu" },
  "Translate to": { es: "Traducir a", fr: "Traduire en", de: "Übersetzen nach", it: "Traduci in", pt: "Traduzir para", nl: "Vertalen naar", pl: "Przetłumacz na" },
