  // ---------------- Preorders list ----------------
  "Variant-level preorder rules with units, ship date, and payment.": { es: "Reglas de prepedido a nivel de variante con unidades, fecha de envío y pago.", fr: "Règles de précommande au niveau de la variante avec unités, date d'expédition et paiement.", de: "Vorbestellregeln auf Variantenebene mit Einheiten, Versanddatum und Zahlung.", it: "Regole di preordine a livello di variante con unità, data di spedizione e pagamento.", pt: "Regras de pré-venda ao nível da variante com unidades, data de envio e pagamento.", nl: "Preorderregels op variantniveau met eenheden, verzenddatum en betaling.", pl: "Reguły przedsprzedaży na poziomie wariantu z jednostkami, datą wysyłki i płatnością." },
  "All": { es: "Todos", fr: "Tous", de: "Alle", it: "Tutti", pt: "Todos", nl: "Alle", pl: "Wszystkie" },
  "Payment mode": { es: "Modo de pago", fr: "Mode de paiement", de: "Zahlungsmodus", it: "Modalità di pagamento", pt: "Modo de pagamento", nl: "Betaalmodus", pl: "Tryb płatności" },
  "Cart behavior": { es: "Comportamiento del carrito", fr: "Comportement du panier", de: "Warenkorb-Verhalten", it: "Comportamento del carrello", pt: "Comportamento do carrinho", nl: "Winkelwagengedrag", pl: "Zachowanie koszyka" },
  "Units sold": { es: "Unidades vendidas", fr: "Unités vendues", de: "Verkaufte Einheiten", it: "Unità vendute", pt: "Unidades vendidas", nl: "Verkochte eenheden", pl: "Sprzedane jednostki" },
  "MOQ gated": { es: "Con MOQ", fr: "Soumis au MOQ", de: "MOQ-gebunden", it: "Vincolato a MOQ", pt: "Com MOQ", nl: "MOQ-gebonden", pl: "Z MOQ" },
  "Hard split": { es: "División estricta", fr: "Séparation stricte", de: "Harte Trennung", it: "Divisione netta", pt: "Divisão rígida", nl: "Harde splitsing", pl: "Twardy podział" },
  "Warning only": { es: "Solo aviso", fr: "Avertissement seulement", de: "Nur Warnung", it: "Solo avviso", pt: "Apenas aviso", nl: "Alleen waarschuwing", pl: "Tylko ostrzeżenie" },
  "Cart": { es: "Carrito", fr: "Panier", de: "Warenkorb", it: "Carrello", pt: "Carrinho", nl: "Winkelwagen", pl: "Koszyk" },
  "Pause": { es: "Pausar", fr: "Mettre en pause", de: "Pausieren", it: "Metti in pausa", pt: "Pausar", nl: "Pauzeren", pl: "Wstrzymaj" },
