for (const [key, m] of Object.entries(RETROFIT)) {
  (Object.keys(m) as Array<Exclude<Locale, "en">>).forEach((loc) => {
    const val = m[loc];
    if (val) DICT[loc][key] = val;
  });
}

type LocaleCtx = {
  locale: Locale;
  setLocale: (l: Locale) => void;
  t: (key: string) => string;
};

const Ctx = createContext<LocaleCtx>({
  locale: STORE_DEFAULT_LOCALE,
  setLocale: () => {},
  t: (k) => EN[k] ?? k,
});

export function LocaleProvider({ children }: { children: ReactNode }) {
  const [locale, setLocaleState] = useState<Locale>(STORE_DEFAULT_LOCALE);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const saved = window.localStorage.getItem("encore_locale") as Locale | null;
    if (saved && saved in DICT) setLocaleState(saved);
  }, []);

  const value = useMemo<LocaleCtx>(
    () => ({
      locale,
      setLocale: (l) => {
        setLocaleState(l);
        if (typeof window !== "undefined") window.localStorage.setItem("encore_locale", l);
      },
      t: (key) => DICT[locale]?.[key] ?? EN[key] ?? key,
    }),
    [locale],
  );

  return <Ctx.Provider value={value}>{children}</Ctx.Provider>;
}

export function useLocale() {
  return useContext(Ctx);
}
